import React, { useState, useRef, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { User, Settings, Lock, LogOut, Trash2, Send, Zap, Mic, Volume2, Shield } from 'lucide-react';
import styles from './HomePage.module.css';
import { useAuth } from '../../auth/context';
import { ANIME_MODEL_IMAGE_PATH } from '../model/animeModelConfig';
import { chatWithAssistantApi, trainAssistantApi } from '../../../shared/api';

const EXPRESSIONS = [
  { key: 'happy', eyes: '^ ^', mouth: 'â—¡', mood: 'Cute' },
  { key: 'smile', eyes: 'â€¢ â€¢', mouth: 'á´—', mood: 'Friendly' },
  { key: 'wink', eyes: '^ -', mouth: 'â— ', mood: 'Playful' },
  { key: 'surprised', eyes: 'o o', mouth: 'o', mood: 'Surprised' },
];

const randomExpression = () => EXPRESSIONS[Math.floor(Math.random() * EXPRESSIONS.length)];

const CHAT_HISTORY_LIMIT = 120;
const CHAT_HISTORY_KEY_PREFIX = 'aipa_chat_history_v1';
const CHAT_SESSION_KEY_PREFIX = 'aipa_chat_session_v1';

const buildWelcomeMessage = (name) => ({
  id: 1,
  sender: 'bot',
  text: `Chao mung tro lai ${name}! Toi la Node AI, ban can ho tro gi hom nay?`,
});

const getHistoryKey = (name) => `${CHAT_HISTORY_KEY_PREFIX}:${name || 'guest'}`;
const getSessionKey = (name) => `${CHAT_SESSION_KEY_PREFIX}:${name || 'guest'}`;

const createSessionId = () => {
  if (typeof window !== 'undefined' && window.crypto && typeof window.crypto.randomUUID === 'function') {
    return window.crypto.randomUUID();
  }
  return `sess-${Date.now().toString(36)}-${Math.random().toString(36).slice(2, 10)}`;
};

const getOrCreateSessionId = (name) => {
  if (typeof window === 'undefined') {
    return 'default-web-session';
  }
  const key = getSessionKey(name);
  const existing = (window.localStorage.getItem(key) || '').trim();
  if (existing) {
    return existing;
  }
  const created = createSessionId();
  window.localStorage.setItem(key, created);
  return created;
};

const loadLocalHistory = (name) => {
  if (typeof window === 'undefined') {
    return [];
  }
  try {
    const raw = window.localStorage.getItem(getHistoryKey(name)) || '[]';
    const parsed = JSON.parse(raw);
    if (!Array.isArray(parsed)) {
      return [];
    }
    return parsed
      .filter((item) => item && (item.sender === 'user' || item.sender === 'bot') && typeof item.text === 'string')
      .slice(-CHAT_HISTORY_LIMIT)
      .map((item, index) => ({
        id: Number(item.id) || Date.now() + index,
        sender: item.sender,
        text: item.text,
      }));
  } catch (_err) {
    return [];
  }
};

const normalizeText = (value) =>
  (value || '')
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .toLowerCase()
    .trim();

const resolveAssistantReply = (prompt, { username, isAdmin }) => {
  const clean = normalizeText(prompt);

  if (!clean) {
    return `MĂ¬nh Ä‘ang nghe Ä‘Ă¢y ${username}. Báº¡n hĂ£y nháº¯n má»™t cĂ¢u há»i cá»¥ thá»ƒ Ä‘á»ƒ mĂ¬nh tráº£ lá»i chi tiáº¿t hÆ¡n.`;
  }

  if (clean.includes('xin chao') || clean.includes('chao') || clean.includes('hello') || clean.includes('hi')) {
    return `ChĂ o ${username}. MĂ¬nh Ä‘Ă£ nháº­n Ä‘Æ°á»£c tin nháº¯n vĂ  sáº½ pháº£n há»“i theo ná»™i dung báº¡n há»i thay vĂ¬ tráº£ lá»i máº·c Ä‘á»‹nh.`;
  }

  if (clean.includes('gio') || clean.includes('ngay') || clean.includes('hom nay') || clean.includes('thu')) {
    const now = new Date();
    const formatted = now.toLocaleString('vi-VN', {
      weekday: 'long',
      day: '2-digit',
      month: '2-digit',
      year: 'numeric',
      hour: '2-digit',
      minute: '2-digit',
    });
    return `Thá»i gian hiá»‡n táº¡i lĂ  ${formatted}.`;
  }

  if (clean.includes('tai khoan') || clean.includes('thong tin') || clean.includes('profile')) {
    return 'Báº¡n cĂ³ thá»ƒ má»Ÿ Settings > ThĂ´ng tin tĂ i khoáº£n Ä‘á»ƒ xem vĂ  cáº­p nháº­t thĂ´ng tin cĂ¡ nhĂ¢n.';
  }

  if (clean.includes('admin') || clean.includes('quan tri')) {
    return isAdmin
      ? 'TĂ i khoáº£n cá»§a báº¡n cĂ³ quyá»n admin. Báº¡n má»Ÿ Settings > Trang quáº£n trá»‹ Ä‘á»ƒ xem user vĂ  lá»‹ch sá»­ khĂ³a tĂ i khoáº£n.'
      : 'TĂ i khoáº£n hiá»‡n táº¡i khĂ´ng cĂ³ quyá»n admin. Náº¿u cáº§n, hĂ£y Ä‘Äƒng nháº­p báº±ng tĂ i khoáº£n ROLE_ADMIN.';
  }

  if (
    clean.includes('model') ||
    clean.includes('mo hinh') ||
    clean.includes('llm') ||
    clean.includes('vosk') ||
    clean.includes('ai free')
  ) {
    return 'Model voice free Vosk Ä‘Ă£ Ä‘Æ°á»£c thĂªm vĂ o thÆ° má»¥c model/. Náº¿u muá»‘n chat AI tháº­t sá»±, cáº§n bá»• sung API chat backend (vĂ­ dá»¥ /api/chat) Ä‘á»ƒ káº¿t ná»‘i LLM.';
  }

  if (clean.includes('dang nhap') || clean.includes('dang ky') || clean.includes('mat khau') || clean.includes('jwt')) {
    return 'Há»‡ thá»‘ng auth hiá»‡n dĂ¹ng JWT. Náº¿u gáº·p lá»—i Ä‘Äƒng nháº­p, báº¡n kiá»ƒm tra token trong localStorage vĂ  endpoint /api/auth/* trĂªn backend.';
  }

  if (clean.includes('test') || clean.includes('build')) {
    return 'Frontend cĂ³ thá»ƒ test báº±ng lá»‡nh: CI=true npm test -- --watchAll=false vĂ  build báº±ng npm run build.';
  }

  return `MĂ¬nh Ä‘Ă£ nháº­n ná»™i dung: "${prompt}". Hiá»‡n táº¡i phiĂªn báº£n nĂ y chÆ°a káº¿t ná»‘i LLM backend nĂªn mĂ¬nh tráº£ lá»i theo trá»£ lĂ½ há»‡ thá»‘ng. Náº¿u báº¡n muá»‘n, mĂ¬nh sáº½ tiáº¿p tá»¥c bá»• sung API chat tháº­t.`;
};

const toChatHistory = (history) =>
  history.slice(-8).map((item) => ({
    sender: item.sender,
    text: item.text,
  }));

const parseTrainingCommand = (text) => {
  const trimmed = (text || '').trim();
  if (!trimmed.toLowerCase().startsWith('/train ')) {
    return null;
  }

  const content = trimmed.slice(7).trim();
  const separatorIndex = content.indexOf('=>');

  if (separatorIndex < 0) {
    return { error: 'Sai cĂº phĂ¡p train. DĂ¹ng: /train cĂ¢u há»i => cĂ¢u tráº£ lá»i' };
  }

  const question = content.slice(0, separatorIndex).trim();
  const answer = content.slice(separatorIndex + 2).trim();

  if (!question || !answer) {
    return { error: 'Dá»¯ liá»‡u train bá»‹ thiáº¿u. DĂ¹ng: /train cĂ¢u há»i => cĂ¢u tráº£ lá»i' };
  }

  return { question, answer };
};

const LoadingDots = () => (
  <div className={styles.loadingDots}>
    <div className={styles.dot}></div>
    <div className={styles.dot}></div>
    <div className={styles.dot}></div>
  </div>
);

const AnimeCompanion = ({ expression, isSpeaking, isRecording, useImageModel, onImageError }) => (
  <div className={styles.animeScene}>
    <div className={`${styles.animeAura} ${isSpeaking ? styles.animeAuraSpeaking : ''}`}></div>
    {useImageModel ? (
      <div className={styles.animeImageWrap}>
        <img
          src={ANIME_MODEL_IMAGE_PATH}
          alt="Anime companion"
          className={styles.animeImage}
          onError={onImageError}
        />
      </div>
    ) : (
      <div className={styles.animeGirl}>
        <div className={styles.animeHair}></div>
        <div className={styles.animeFace}>
          <div className={styles.animeEyes}>{expression.eyes}</div>
          <div className={styles.animeMouth}>{expression.mouth}</div>
        </div>
        <div className={styles.animeBody}></div>
      </div>
    )}

    <div className={styles.modelPlaceholder}>
      {isRecording ? 'Äang láº¯ng nghe lá»‡nh...' : `Anime Assistant - ${expression.mood}`}
    </div>
  </div>
);

const SettingsPopover = ({ userData, handleAction, isSettingsOpen, isAdmin }) => (
  <div className={`${styles.settingsPopover} ${isSettingsOpen ? styles.active : ''}`}>
    <p className="text-gray-400 text-sm mb-3">
      **{userData.name}** ({userData.email})
    </p>
    <hr className="border-gray-700 mb-2" />

    <div className={styles.popoverItem} onClick={() => handleAction('profile')}>
      <User size={16} style={{ marginRight: '10px' }} />
      Thong tin tai khoan
    </div>
    <div className={styles.popoverItem} onClick={() => handleAction('privacy')}>
      <Lock size={16} style={{ marginRight: '10px' }} />
      Thay doi quyen rieng tu
    </div>
    {isAdmin && (
      <div className={styles.popoverItem} onClick={() => handleAction('admin')}>
        <Shield size={16} style={{ marginRight: '10px' }} />
        Trang quan tri
      </div>
    )}
    <div className={styles.popoverItem} onClick={() => handleAction('delete')}>
      <Trash2 size={16} style={{ marginRight: '10px' }} />
      Xoa tai khoan (Nguy hiem)
    </div>
    <div className={`${styles.popoverItem} ${styles.logout}`} onClick={() => handleAction('logout')}>
      <LogOut size={16} style={{ marginRight: '10px' }} />
      Dang xuat
    </div>
  </div>
);

const HomePage = () => {
  const navigate = useNavigate();
  const { currentUser, auth, logout } = useAuth();
  const isAdmin = auth?.role === 'ROLE_ADMIN';

  const username = currentUser?.username || 'Nguoi dung';
  const userData = {
    name: username,
    email: currentUser?.email || `${username}@local`,
  };

  const [messages, setMessages] = useState(() => [buildWelcomeMessage(username)]);
  const [input, setInput] = useState('');
  const [isSettingsOpen, setIsSettingsOpen] = useState(false);
  const [isBotTyping, setIsBotTyping] = useState(false);
  const [isRecording, setIsRecording] = useState(false);
  const [isSpeaking, setIsSpeaking] = useState(false);
  const [expression, setExpression] = useState(() => randomExpression());
  const [hasModelImageError, setHasModelImageError] = useState(false);

  const chatAreaRef = useRef(null);
  const expressionTimerRef = useRef(null);
  const recognitionRef = useRef(null);
  const sessionIdRef = useRef(getOrCreateSessionId(username));

  useEffect(() => {
    sessionIdRef.current = getOrCreateSessionId(username);
    const storedMessages = loadLocalHistory(username);
    if (storedMessages.length > 0) {
      setMessages(storedMessages);
      return;
    }
    setMessages([buildWelcomeMessage(username)]);
  }, [username]);

  useEffect(() => {
    if (typeof window === 'undefined') {
      return;
    }
    try {
      const compact = messages
        .slice(-CHAT_HISTORY_LIMIT)
        .map((item) => ({ id: item.id, sender: item.sender, text: item.text }));
      window.localStorage.setItem(getHistoryKey(username), JSON.stringify(compact));
    } catch (_err) {
      // Ignore localStorage write errors (private mode/quota).
    }
  }, [messages, username]);

  useEffect(() => {
    if (chatAreaRef.current) {
      chatAreaRef.current.scrollTop = chatAreaRef.current.scrollHeight;
    }
  }, [messages, isBotTyping]);

  useEffect(() => {
    expressionTimerRef.current = setInterval(() => {
      setExpression(randomExpression());
    }, 4000);

    return () => {
      if (expressionTimerRef.current) {
        clearInterval(expressionTimerRef.current);
      }
      if (recognitionRef.current) {
        recognitionRef.current.onresult = null;
        recognitionRef.current.onerror = null;
        recognitionRef.current.onend = null;
        recognitionRef.current.stop();
        recognitionRef.current = null;
      }
      if (typeof window !== 'undefined' && window.speechSynthesis) {
        window.speechSynthesis.cancel();
      }
    };
  }, []);

  const speakText = (text) => {
    if (typeof window === 'undefined' || !window.speechSynthesis || !text) return;

    window.speechSynthesis.cancel();

    const utterance = new window.SpeechSynthesisUtterance(text);
    utterance.lang = 'vi-VN';
    utterance.rate = 1;
    utterance.pitch = 1.05;

    const voices = window.speechSynthesis.getVoices();
    const vietnameseVoice = voices.find((voice) => voice.lang.toLowerCase().startsWith('vi'));
    if (vietnameseVoice) {
      utterance.voice = vietnameseVoice;
    }

    utterance.onstart = () => {
      setIsSpeaking(true);
      setExpression(randomExpression());
    };
    utterance.onend = () => {
      setIsSpeaking(false);
    };
    utterance.onerror = () => {
      setIsSpeaking(false);
    };

    window.speechSynthesis.speak(utterance);
  };

  const handleBotResponse = async (userPrompt, historySnapshot = []) => {
    setIsBotTyping(true);

    const startedAt = Date.now();
    let answer = '';

    try {
      const response = await chatWithAssistantApi({
        prompt: userPrompt,
        history: toChatHistory(historySnapshot),
        session_id: sessionIdRef.current,
      });
      answer = (response?.answer || '').trim();
    } catch (_error) {
      answer = `${resolveAssistantReply(userPrompt, { username, isAdmin })}\n(LÆ°u Ă½: AI service trong aipa_controll chÆ°a cháº¡y hoáº·c khĂ´ng káº¿t ná»‘i Ä‘Æ°á»£c.)`;
    }

    if (!answer) {
      answer = resolveAssistantReply(userPrompt, { username, isAdmin });
    }

    const elapsed = Date.now() - startedAt;
    if (elapsed < 450) {
      await new Promise((resolve) => setTimeout(resolve, 450 - elapsed));
    }

    const botResponse = {
      id: Date.now() + 1,
      sender: 'bot',
      text: answer,
    };

    setMessages((prev) => [...prev, botResponse]);
    setExpression(randomExpression());
    setIsBotTyping(false);
    speakText(botResponse.text);
  };

  const handleTrainCommand = async (trainPayload) => {
    setIsBotTyping(true);

    let answer = '';

    if (trainPayload.error) {
      answer = trainPayload.error;
    } else {
      try {
        const response = await trainAssistantApi(trainPayload);
        answer = `${response?.message || 'ÄĂ£ train xong.'} Tá»« bĂ¢y giá» AI sáº½ Æ°u tiĂªn tráº£ lá»i cĂ¢u nĂ y.`;
      } catch (error) {
        answer = `Train tháº¥t báº¡i: ${error?.message || 'KhĂ´ng káº¿t ná»‘i Ä‘Æ°á»£c AI service.'}`;
      }
    }

    const botResponse = {
      id: Date.now() + 1,
      sender: 'bot',
      text: answer,
    };

    setMessages((prev) => [...prev, botResponse]);
    setExpression(randomExpression());
    setIsBotTyping(false);
    speakText(botResponse.text);
  };

  const submitPrompt = (rawPrompt, displayText = null) => {
    const messageText = (rawPrompt || '').trim();
    if (!messageText) return;

    const userBubbleText = displayText || messageText;
    const newMessage = { id: Date.now(), sender: 'user', text: userBubbleText };
    let historySnapshot = [];

    setMessages((prev) => {
      historySnapshot = [...prev, newMessage];
      return historySnapshot;
    });

    const trainingPayload = parseTrainingCommand(messageText);
    if (trainingPayload) {
      handleTrainCommand(trainingPayload);
      return;
    }

    handleBotResponse(messageText, historySnapshot);
  };

  const handleSend = (e) => {
    e.preventDefault();
    if (!input.trim() || isRecording) return;
    const messageText = input.trim();
    setInput('');
    submitPrompt(messageText);
  };

  const handleMicToggle = () => {
    if (isBotTyping) return;

    if (!isRecording) {
      const SpeechRecognition = window.SpeechRecognition || window.webkitSpeechRecognition;
      if (!SpeechRecognition) {
        setMessages((prev) => [
          ...prev,
          {
            id: Date.now() + 1,
            sender: 'bot',
              text: 'TrĂ¬nh duyá»‡t hiá»‡n táº¡i khĂ´ng há»— trá»£ nháº­n diá»‡n giá»ng nĂ³i.',
          },
        ]);
        return;
      }

      const recognition = new SpeechRecognition();
      recognition.lang = 'vi-VN';
      recognition.continuous = false;
      recognition.interimResults = false;
      recognition.maxAlternatives = 1;

      recognitionRef.current = recognition;
      setIsRecording(true);
      setExpression(randomExpression());

      recognition.onresult = (event) => {
        const transcript = Array.from(event.results || [])
          .map((result) => result?.[0]?.transcript || '')
          .join(' ')
          .trim();

        if (!transcript) {
          setMessages((prev) => [
            ...prev,
            {
              id: Date.now() + 1,
              sender: 'bot',
              text: 'MĂ¬nh chÆ°a nghe rĂµ ná»™i dung. Báº¡n thá»­ nĂ³i cháº­m hÆ¡n nhĂ©.',
            },
          ]);
          return;
        }

        submitPrompt(transcript, `(Voice Command): ${transcript}`);
      };

      recognition.onerror = (event) => {
        const message = event?.error === 'not-allowed'
          ? 'Báº¡n chÆ°a cáº¥p quyá»n microphone cho trĂ¬nh duyá»‡t.'
          : 'KhĂ´ng thá»ƒ nháº­n diá»‡n giá»ng nĂ³i. Báº¡n thá»­ láº¡i.';

        setMessages((prev) => [
          ...prev,
          {
            id: Date.now() + 1,
            sender: 'bot',
            text: message,
          },
        ]);
      };

      recognition.onend = () => {
        setIsRecording(false);
        recognitionRef.current = null;
      };

      recognition.start();
    } else {
      if (recognitionRef.current) {
        recognitionRef.current.stop();
      }
      setIsRecording(false);
    }
  };

  const handleSettingsAction = (action) => {
    setIsSettingsOpen(false);

    if (action === 'logout') {
      logout();
      navigate('/', { replace: true });
      return;
    }

    if (action === 'profile') {
      navigate('/userInfo');
      return;
    }

    if (action === 'privacy') {
      return;
    }

    if (action === 'admin') {
      navigate('/admin');
    }
  };

  return (
    <div className={styles.homePageContainer}>
      <header className={styles.header}>
        <h1 className={styles.headerTitle}>
          AIPA INTERFACE <Zap size={18} style={{ display: 'inline', color: '#00bcd4' }} />
        </h1>

        <div style={{ position: 'relative' }}>
          <button className={styles.profileButton} onClick={() => setIsSettingsOpen(!isSettingsOpen)}>
            <Settings size={20} />
          </button>

          <SettingsPopover
            userData={userData}
            handleAction={handleSettingsAction}
            isSettingsOpen={isSettingsOpen}
            isAdmin={isAdmin}
          />
        </div>
      </header>

      <div className={styles.mainContent}>
        <div className={styles.botArea}>
          <div className={styles.botImage}>
            <AnimeCompanion
              expression={expression}
              isSpeaking={isSpeaking}
              isRecording={isRecording}
              useImageModel={!hasModelImageError}
              onImageError={() => setHasModelImageError(true)}
            />
          </div>

          <div className={styles.botInfo}>
            <p className={styles.botName}>Anime AI Assistant</p>
            <p className={styles.botStatus} style={{ color: isRecording ? '#ef4444' : isSpeaking ? '#00bcd4' : '#48bb78' }}>
              &#9679; {isRecording ? 'ÄANG GHI Ă‚M' : isSpeaking ? 'ÄANG Äá»ŒC PHáº¢N Há»’I' : 'Trá»±c tuyáº¿n - Sáºµn sĂ ng'}
            </p>
            <p className="text-sm text-gray-500 mt-4">
              <Volume2 size={14} style={{ display: 'inline', marginRight: '6px' }} />
              Tá»± Ä‘á»™ng Ä‘á»c cĂ¢u tráº£ lá»i, thay Ä‘á»•i biá»ƒu cáº£m ngáº«u nhiĂªn.
            </p>
          </div>
        </div>

        <div className={styles.chatArea} ref={chatAreaRef}>
          {messages.map((msg) => (
            <div key={msg.id} className={`${styles.messageBubble} ${msg.sender === 'user' ? styles.userMessage : styles.botMessage}`}>
              {msg.text}
            </div>
          ))}

          {isBotTyping && (
            <div className={styles.botMessage} style={{ maxWidth: '100px', padding: 0 }}>
              <LoadingDots />
            </div>
          )}
        </div>
      </div>

      <footer className={styles.footer}>
        <form onSubmit={handleSend} style={{ display: 'flex', width: '100%', gap: '10px' }}>
          <input
            type="text"
            placeholder="Nháº­p vÄƒn báº£n hoáº·c dĂ¹ng Micro..."
            className={styles.chatInput}
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={(e) => {
              if (e.key === 'Enter' && !e.shiftKey) {
                handleSend(e);
              }
            }}
            disabled={isBotTyping || isRecording}
          />

          {input.trim() ? (
            <button type="submit" className={styles.sendButton} disabled={isBotTyping || isRecording}>
              <Send size={20} fill="white" />
            </button>
          ) : (
            <button type="button" className={`${styles.micButton} ${isRecording ? styles.active : ''}`} onClick={handleMicToggle} disabled={isBotTyping}>
              <Mic size={20} color="white" />
            </button>
          )}
        </form>
      </footer>
    </div>
  );
};

export default HomePage;
